     3→
     4→using Azure;
     5→using Azure.Data.Tables;
     6→using Azure.ResourceManager.Resources;
     7→using Azure.ResourceManager.Storage;
     8→using Azure.ResourceManager.Storage.Models;
     9→using Azure.Storage.Blobs;
    10→using Azure.Storage.Blobs.Models;
    11→using Azure.Storage.Files.DataLake;
    12→using AzureMcp.Areas.Storage.Models;
    13→using AzureMcp.Options;
    14→using AzureMcp.Services.Azure;
    15→using AzureMcp.Services.Azure.Subscription;
    16→using AzureMcp.Services.Azure.Tenant;
    17→using AzureMcp.Services.Caching;
    18→
    19→namespace AzureMcp.Areas.Storage.Services;
    20→
    21→public class StorageService(ISubscriptionService subscriptionService, ITenantService tenantService, ICacheService cacheService) : BaseAzureService(tenantService), IStorageService
    22→{
    23→    private readonly ISubscriptionService _subscriptionService = subscriptionService ?? throw new ArgumentNullException(nameof(subscriptionService));
    24→    private readonly ICacheService _cacheService = cacheService ?? throw new ArgumentNullException(nameof(cacheService));
    25→    private const string CacheGroup = "storage";
    26→    private const string StorageAccountsCacheKey = "accounts";
    27→    private static readonly TimeSpan s_cacheDuration = TimeSpan.FromHours(1);
    28→
    29→    public async Task<List<string>> GetStorageAccounts(string subscriptionId, string? tenant = null, RetryPolicyOptions? retryPolicy = null)
    30→    {
    31→        ValidateRequiredParameters(subscriptionId);
    32→
    33→        // Create cache key
    34→        var cacheKey = string.IsNullOrEmpty(tenant)
    35→            ? $"{StorageAccountsCacheKey}_{subscriptionId}"
    36→            : $"{StorageAccountsCacheKey}_{subscriptionId}_{tenant}";
    37→
    38→        // Try to get from cache first
    39→        var cachedAccounts = await _cacheService.GetAsync<List<string>>(CacheGroup, cacheKey, s_cacheDuration);
    40→        if (cachedAccounts != null)
    41→        {
    42→            return cachedAccounts;
    43→        }
    44→
    45→        var subscription = await _subscriptionService.GetSubscription(subscriptionId, tenant, retryPolicy);
    46→        var accounts = new List<string>();
    47→        try
    48→        {
    49→            await foreach (var account in subscription.GetStorageAccountsAsync())
    50→            {
    51→                if (account?.Data?.Name != null)
    52→                {
    53→                    accounts.Add(account.Data.Name);
    54→                }
    55→            }
    56→
    57→            // Cache the results
    58→            await _cacheService.SetAsync(CacheGroup, cacheKey, accounts, s_cacheDuration);
    59→        }
    60→        catch (Exception ex)
    61→        {
    62→            throw new Exception($"Error retrieving Storage accounts: {ex.Message}", ex);
    63→        }
    64→
    65→        return accounts;
    66→    }
    67→
    68→    public async Task<List<string>> ListContainers(string accountName, string subscriptionId, string? tenant = null, RetryPolicyOptions? retryPolicy = null)
    69→    {
    70→        ValidateRequiredParameters(accountName, subscriptionId);
    71→
    72→        var blobServiceClient = await CreateBlobServiceClient(accountName, tenant, retryPolicy);
    73→        var containers = new List<string>();
    74→
    75→        try
    76→        {
    77→            await foreach (var container in blobServiceClient.GetBlobContainersAsync())
    78→            {
    79→                containers.Add(container.Name);
    80→            }
    81→        }
    82→        catch (Exception ex)
    83→        {
    84→            throw new Exception($"Error listing containers: {ex.Message}", ex);
    85→        }
    86→
    87→        return containers;
    88→    }
    89→
    90→    public async Task<List<string>> ListTables(
    91→        string accountName,
    92→        string subscriptionId,
    93→        AuthMethod authMethod = AuthMethod.Credential,
    94→        string? connectionString = null,
    95→        string? tenant = null,
    96→        RetryPolicyOptions? retryPolicy = null)
    97→    {
    98→        ValidateRequiredParameters(accountName, subscriptionId);
    99→
   100→        var tables = new List<string>();
   101→
   102→        try
   103→        {
   104→            // First attempt with requested auth method
   105→            var tableServiceClient = await CreateTableServiceClientWithAuth(
   106→                accountName,
   107→                subscriptionId,
   108→                authMethod,
   109→                connectionString,
   110→                tenant,
   111→                retryPolicy);
   112→
   113→            await foreach (var table in tableServiceClient.QueryAsync())
   114→            {
   115→                tables.Add(table.Name);
   116→            }
   117→            return tables;
   118→        }
   119→        catch (Exception ex) when (
   120→            authMethod == AuthMethod.Credential &&
   121→            ex is RequestFailedException rfEx &&
   122→            (rfEx.Status == 403 || rfEx.Status == 401))
   123→        {
   124→            try
   125→            {
   126→                // If credential auth fails with 403/401, try key auth
   127→                var keyClient = await CreateTableServiceClientWithAuth(
   128→                    accountName, subscriptionId, AuthMethod.Key, connectionString, tenant, retryPolicy);
   129→
   130→                tables.Clear(); // Reset the list for reuse
   131→                await foreach (var table in keyClient.QueryAsync())
   132→                {
   133→                    tables.Add(table.Name);
   134→                }
   135→                return tables;
   136→            }
   137→            catch (Exception keyEx) when (keyEx is RequestFailedException keyRfEx && keyRfEx.Status == 403)
   138→            {
   139→                // If key auth fails with 403, try connection string
   140→                var connStringClient = await CreateTableServiceClientWithAuth(
   141→                    accountName, subscriptionId, AuthMethod.ConnectionString, connectionString, tenant, retryPolicy);
   142→
   143→                tables.Clear(); // Reset the list for reuse
   144→                await foreach (var table in connStringClient.QueryAsync())
   145→                {
   146→                    tables.Add(table.Name);
   147→                }
   148→                return tables;
   149→            }
   150→            catch (Exception keyEx)
   151→            {
   152→                throw new Exception($"Error listing tables with key auth: {keyEx.Message}", keyEx);
   153→            }
   154→        }
   155→        catch (Exception ex) when (
   156→            authMethod == AuthMethod.Key &&
   157→            ex is RequestFailedException rfEx && rfEx.Status == 403)
   158→        {
   159→            try
   160→            {
   161→                // If key auth fails with 403, try connection string
   162→                var connStringClient = await CreateTableServiceClientWithAuth(
   163→                    accountName, subscriptionId, AuthMethod.ConnectionString, connectionString, tenant, retryPolicy);
   164→
   165→                tables.Clear(); // Reset the list for reuse
   166→                await foreach (var table in connStringClient.QueryAsync())
   167→                {
   168→                    tables.Add(table.Name);
   169→                }
   170→                return tables;
   171→            }
   172→            catch (Exception connStringEx)
   173→            {
   174→                throw new Exception($"Error listing tables with connection string: {connStringEx.Message}", connStringEx);
   175→            }
   176→        }
   177→        catch (Exception ex)
   178→        {
   179→            throw new Exception($"Error listing tables: {ex.Message}", ex);
   180→        }
   181→    }
   182→
   183→    public async Task<List<string>> ListBlobs(string accountName, string containerName, string subscriptionId, string? tenant = null, RetryPolicyOptions? retryPolicy = null)
   184→    {
   185→        ValidateRequiredParameters(accountName, containerName, subscriptionId);
   186→
   187→        var blobServiceClient = await CreateBlobServiceClient(accountName, tenant, retryPolicy);
   188→        var containerClient = blobServiceClient.GetBlobContainerClient(containerName);
   189→        var blobs = new List<string>();
   190→
   191→        try
   192→        {
   193→            await foreach (var blob in containerClient.GetBlobsAsync())
   194→            {
   195→                blobs.Add(blob.Name);
   196→            }
   197→        }
   198→        catch (Exception ex)
   199→        {
   200→            throw new Exception($"Error listing blobs: {ex.Message}", ex);
   201→        }
   202→
   203→        return blobs;
   204→    }
   205→
   206→    public async Task<BlobContainerProperties> GetContainerDetails(
   207→        string accountName,
   208→        string containerName,
   209→        string subscriptionId,
   210→        string? tenant = null,
   211→        RetryPolicyOptions? retryPolicy = null)
   212→    {
   213→        ValidateRequiredParameters(accountName, containerName);
   214→
   215→        var blobServiceClient = await CreateBlobServiceClient(accountName, tenant, retryPolicy);
   216→        var containerClient = blobServiceClient.GetBlobContainerClient(containerName);
   217→
   218→        try
   219→        {
   220→            var properties = await containerClient.GetPropertiesAsync();
   221→            return properties.Value;
   222→        }
   223→        catch (Exception ex)
   224→        {
   225→            throw new Exception($"Error getting container details: {ex.Message}", ex);
   226→        }
   227→    }
   228→
   229→    private async Task<string> GetStorageAccountKey(string accountName, string subscriptionId, string? tenant = null)
   230→    {
   231→        var subscription = await _subscriptionService.GetSubscription(subscriptionId, tenant);
   232→        var storageAccount = await GetStorageAccount(subscription, accountName) ??
   233→            throw new Exception($"Storage account '{accountName}' not found in subscription '{subscriptionId}'");
   234→
   235→        var keys = new List<StorageAccountKey>();
   236→        await foreach (var key in storageAccount.GetKeysAsync())
   237→        {
   238→            keys.Add(key);
   239→        }
   240→
   241→        var firstKey = keys.FirstOrDefault() ?? throw new Exception($"No keys found for storage account '{accountName}'");
   242→        return firstKey.Value;
   243→    }
   244→
   245→    private async Task<string> GetStorageAccountConnectionString(string accountName, string subscriptionId, string? tenant = null)
   246→    {
   247→        var subscription = await _subscriptionService.GetSubscription(subscriptionId, tenant);
   248→        var storageAccount = await GetStorageAccount(subscription, accountName) ??
   249→            throw new Exception($"Storage account '{accountName}' not found in subscription '{subscriptionId}'");
   250→
   251→        var keys = new List<StorageAccountKey>();
   252→        await foreach (var key in storageAccount.GetKeysAsync())
   253→        {
   254→            keys.Add(key);
   255→        }
   256→
   257→        var firstKey = keys.FirstOrDefault() ?? throw new Exception($"No keys found for storage account '{accountName}'");
   258→        return $"DefaultEndpointsProtocol=https;AccountName={accountName};AccountKey={firstKey.Value};EndpointSuffix=core.windows.net";
   259→    }
   260→
   261→    // Helper method to get storage account
   262→    private static async Task<StorageAccountResource?> GetStorageAccount(SubscriptionResource subscription, string accountName)
   263→    {
   264→        await foreach (var account in subscription.GetStorageAccountsAsync())
   265→        {
   266→            if (account.Data.Name == accountName)
   267→            {
   268→                return account;
   269→            }
   270→        }
   271→        return null;
   272→    }
   273→
   274→    protected async Task<TableServiceClient> CreateTableServiceClientWithAuth(
   275→        string accountName,
   276→        string subscriptionId,
   277→        AuthMethod authMethod,
   278→        string? connectionString = null,
   279→        string? tenant = null,
   280→        RetryPolicyOptions? retryPolicy = null)
   281→    {
   282→        var options = ConfigureRetryPolicy(AddDefaultPolicies(new TableClientOptions()), retryPolicy);
   283→
   284→        switch (authMethod)
   285→        {
   286→            case AuthMethod.Key:
   287→                var key = await GetStorageAccountKey(accountName, subscriptionId, tenant);
   288→                var uri = $"https://{accountName}.table.core.windows.net";
   289→                return new TableServiceClient(new Uri(uri), new TableSharedKeyCredential(accountName, key), options);
   290→
   291→            case AuthMethod.ConnectionString:
   292→                var connString = await GetStorageAccountConnectionString(accountName, subscriptionId, tenant);
   293→                return new TableServiceClient(connString, options);
   294→
   295→            case AuthMethod.Credential:
   296→            default:
   297→                var defaultUri = $"https://{accountName}.table.core.windows.net";
   298→                return new TableServiceClient(new Uri(defaultUri), await GetCredential(tenant), options);
   299→        }
   300→    }
   301→
   302→    private async Task<BlobServiceClient> CreateBlobServiceClient(string accountName, string? tenant = null, RetryPolicyOptions? retryPolicy = null)
   303→    {
   304→        var uri = $"https://{accountName}.blob.core.windows.net";
   305→        var options = ConfigureRetryPolicy(AddDefaultPolicies(new BlobClientOptions()), retryPolicy);
   306→        return new BlobServiceClient(new Uri(uri), await GetCredential(tenant), options);
   307→    }
   308→
   309→    private async Task<DataLakeServiceClient> CreateDataLakeServiceClient(string accountName, string? tenant = null, RetryPolicyOptions? retryPolicy = null)
   310→    {
   311→        var uri = $"https://{accountName}.dfs.core.windows.net";
   312→        var options = ConfigureRetryPolicy(AddDefaultPolicies(new DataLakeClientOptions()), retryPolicy);
   313→        return new DataLakeServiceClient(new Uri(uri), await GetCredential(tenant), options);
   314→    }
   315→
   316→    public async Task<List<DataLakePathInfo>> ListDataLakePaths(
   317→        string accountName,
   318→        string fileSystemName,
   319→        string subscriptionId,
   320→        string? tenant = null,
   321→        RetryPolicyOptions? retryPolicy = null)
   322→    {
   323→        ValidateRequiredParameters(accountName, fileSystemName, subscriptionId);
   324→
   325→        var dataLakeServiceClient = await CreateDataLakeServiceClient(accountName, tenant, retryPolicy);
   326→        var fileSystemClient = dataLakeServiceClient.GetFileSystemClient(fileSystemName);
   327→        var paths = new List<DataLakePathInfo>();
   328→
   329→        try
   330→        {
   331→            await foreach (var pathItem in fileSystemClient.GetPathsAsync())
   332→            {
   333→                var pathInfo = new DataLakePathInfo(
   334→                    pathItem.Name,
   335→                    pathItem.IsDirectory == true ? "directory" : "file",
   336→                    pathItem.ContentLength,
   337→                    pathItem.LastModified,
   338→                    pathItem.ETag.ToString());
   339→
   340→                paths.Add(pathInfo);
   341→            }
   342→        }
   343→        catch (Exception ex)
   344→        {
   345→            throw new Exception($"Error listing Data Lake paths: {ex.Message}", ex);
   346→        }
   347→
   348→        return paths;
   349→    }
   350→}
   351→

