            context.Response.Message = $"Successfully created directory '{options.DirectoryPath}' in file system '{options.FileSystem}'";
        }
        catch (Exception ex)
        {
            // Log error with all relevant context
            _logger.LogError(ex,
                "Error creating Data Lake directory. Account: {Account}, FileSystem: {FileSystem}, Directory: {Directory}, Options: {@Options}",
                options.AccountName, options.FileSystem, options.DirectoryPath, options);
            HandleException(context.Response, ex);
        }

        return context.Response;
    }

    // Implementation-specific error handling
    protected override string GetErrorMessage(Exception ex) => ex switch
    {
        RequestFailedException reqEx when reqEx.Status == 404 =>
            "File system or storage account not found. Verify the resource exists and you have access.",
        RequestFailedException reqEx when reqEx.Status == 403 =>
            $"Authorization failed accessing the storage account. Details: {reqEx.Message}",
        RequestFailedException reqEx when reqEx.Status == 409 =>
            "Directory already exists or there was a conflict.",
        RequestFailedException reqEx => reqEx.Message,
        _ => base.GetErrorMessage(ex)
    };

    protected override int GetStatusCode(Exception ex) => ex switch
    {
        RequestFailedException reqEx => reqEx.Status,
        _ => base.GetStatusCode(ex)
    };
}

