using AzureMcp.Areas.Storage.Commands.DataLake.Directory;
using AzureMcp.Areas.Storage.Options.DataLake.Directory;
using AzureMcp.Areas.Storage.Services;
using Microsoft.Extensions.Logging;
using NSubstitute;

namespace AzureMcp.Areas.Storage.UnitTests.DataLake.Directory;

public class DirectoryCreateCommandTests
{
    private readonly IServiceProvider _serviceProvider;
    private readonly IStorageService _storageService;
    private readonly ILogger<DirectoryCreateCommand> _logger;
    private readonly DirectoryCreateCommand _command;

    public DirectoryCreateCommandTests()
    {
        _storageService = Substitute.For<IStorageService>();
        _logger = Substitute.For<ILogger<DirectoryCreateCommand>>();

        var serviceCollection = new ServiceCollection();
        serviceCollection.AddSingleton(_storageService);
        _serviceProvider = serviceCollection.BuildServiceProvider();

        _command = new DirectoryCreateCommand(_logger);
    }

    [Fact]
    public void Constructor_InitializesCommandCorrectly()
    {
        var command = _command.GetCommand();
        Assert.Equal("create", command.Name);
        Assert.NotNull(command.Description);
        Assert.NotEmpty(command.Description);
    }

    [Theory]
    [InlineData("--subscription test-sub --account-name test-account --file-system-name test-fs --directory-path test/dir", true)]
    [InlineData("--subscription test-sub --account-name test-account --file-system-name test-fs", false)]
    [InlineData("--subscription test-sub --directory-path test/dir", false)]
    [InlineData("--directory-path test/dir", false)]
    public async Task ExecuteAsync_ValidatesInputCorrectly(string args, bool shouldSucceed)
    {
        // Arrange
        if (shouldSucceed)
        {
            _storageService.CreateDataLakeDirectory(
                Arg.Any<string>(), Arg.Any<string>(), Arg.Any<string>(),
                Arg.Any<string>(), Arg.Any<string?>(), Arg.Any<RetryPolicyOptions?>())
                .Returns(Task.CompletedTask);
        }

        var context = new CommandContext(_serviceProvider);
        var parseResult = _command.GetCommand().Parse(args);

        // Act
        var response = await _command.ExecuteAsync(context, parseResult);

        // Assert
        Assert.Equal(shouldSucceed ? 200 : 400, response.Status);
        if (shouldSucceed)
        {
            Assert.NotNull(response.Message);
            Assert.Contains("Successfully created directory", response.Message);
        }
        else
        {
            Assert.Contains("required", response.Message!.ToLower());
        }
    }

    [Fact]
    public async Task ExecuteAsync_CallsServiceWithCorrectParameters()
    {
        // Arrange
        string capturedAccountName = null!;
        string capturedFileSystemName = null!;
        string capturedDirectoryPath = null!;
        string capturedSubscription = null!;

        await _storageService.CreateDataLakeDirectory(
            Arg.Do<string>(x => capturedAccountName = x),
            Arg.Do<string>(x => capturedFileSystemName = x),
            Arg.Do<string>(x => capturedDirectoryPath = x),
            Arg.Do<string>(x => capturedSubscription = x),
            Arg.Any<string?>(),
            Arg.Any<RetryPolicyOptions?>())
            .Returns(Task.CompletedTask);

        var context = new CommandContext(_serviceProvider);
        var parseResult = _command.GetCommand().Parse(
            "--subscription test-sub --account-name test-account --file-system-name test-fs --directory-path test/directory");

        // Act
        var response = await _command.ExecuteAsync(context, parseResult);

        // Assert
        Assert.Equal(200, response.Status);
        Assert.Equal("test-account", capturedAccountName);
        Assert.Equal("test-fs", capturedFileSystemName);
        Assert.Equal("test/directory", capturedDirectoryPath);
        Assert.Equal("test-sub", capturedSubscription);

        await _storageService.Received(1).CreateDataLakeDirectory(
            "test-account", "test-fs", "test/directory", "test-sub", null, null);
    }

    [Fact]
    public async Task ExecuteAsync_HandlesServiceErrors()
    {
        // Arrange
        var expectedException = new Exception("Directory creation failed");
        _storageService.CreateDataLakeDirectory(
            Arg.Any<string>(), Arg.Any<string>(), Arg.Any<string>(),
            Arg.Any<string>(), Arg.Any<string?>(), Arg.Any<RetryPolicyOptions?>())
            .Returns(Task.FromException(expectedException));

        var context = new CommandContext(_serviceProvider);
        var parseResult = _command.GetCommand().Parse(
            "--subscription test-sub --account-name test-account --file-system-name test-fs --directory-path test/dir");

        // Act
        var response = await _command.ExecuteAsync(context, parseResult);

        // Assert
        Assert.Equal(500, response.Status);
        Assert.Contains("failed", response.Message!.ToLower());
    }

    [Fact]
    public void OptionsBind_CorrectlyBindsAllParameters()
    {
        // Arrange
        var parseResult = _command.GetCommand().Parse(
            "--subscription test-sub --account-name test-account --file-system-name test-fs --directory-path test/dir");

        // Act
        var options = _command.BindOptions(parseResult);

        // Assert
        Assert.Equal("test-sub", options.Subscription);
        Assert.Equal("test-account", options.AccountName);
        Assert.Equal("test-fs", options.FileSystem);
        Assert.Equal("test/dir", options.DirectoryPath);
    }
}

